import { useState, useEffect } from "react";
import toast from "react-hot-toast";
import { useAuth } from "../../context/AuthContext";
import { Modal, Field, Alert } from "../common/UI";
import { TEAMS, STATUS_LABELS, PRIORITY_LABELS } from "../../utils/constants";
import api from "../../utils/api";

export default function TaskForm({ open, onClose, onSaved, task }) {
  const { user }  = useAuth();
  const isEdit    = !!task;

  const [form, setForm] = useState({
    title: "", description: "", assignedTo: "",
    team: user?.team || TEAMS[0], status: "todo", priority: "medium",
    dueDate: "", statusNote: "",
  });
  const [assignableUsers, setAssignable] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error,   setError]   = useState("");

  useEffect(() => {
    api.get("/users/assignable")
      .then((r) => {
        setAssignable(r.data.users);
        // Default: select self
        if (!isEdit && r.data.users.length > 0) {
          const self = r.data.users.find((u) => u._id === user?._id);
          setForm((f) => ({ ...f, assignedTo: self?._id || r.data.users[0]._id }));
        }
      })
      .catch(console.error);
  }, [open]);

  useEffect(() => {
    if (task) {
      setForm({
        title:       task.title || "",
        description: task.description || "",
        assignedTo:  task.assignedTo?._id || task.assignedTo || "",
        team:        task.team || TEAMS[0],
        status:      task.status || "todo",
        priority:    task.priority || "medium",
        dueDate:     task.dueDate ? task.dueDate.slice(0, 10) : "",
        statusNote:  "",
      });
    }
    setError("");
  }, [task, open]);

  const set = (k) => (e) => setForm((f) => ({ ...f, [k]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    if (!form.title.trim()) return setError("Task title is required.");
    if (!form.assignedTo)   return setError("Please select who to assign this task to.");
    if (!form.dueDate)      return setError("Due date is required.");

    setLoading(true);
    try {
      const payload = { ...form };
      if (isEdit) {
        await api.put(`/tasks/${task._id}`, payload);
        toast.success("Task updated!");
      } else {
        await api.post("/tasks", payload);
        toast.success("Task created!");
      }
      onSaved();
      onClose();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to save task.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Modal open={open} onClose={onClose} title={isEdit ? "Edit Task" : "Create New Task"} width={580}>
      <Alert type="error" message={error} />
      <form onSubmit={handleSubmit}>
        <Field label="Task Title" required>
          <input placeholder="What needs to be done?" value={form.title} onChange={set("title")} />
        </Field>

        <Field label="Description">
          <textarea
            placeholder="Add more details, context, or acceptance criteria..."
            value={form.description} onChange={set("description")}
            style={{ minHeight: 80 }}
          />
        </Field>

        <div className="field-row">
          <Field label="Assign To" required>
            <select value={form.assignedTo} onChange={set("assignedTo")}>
              <option value="">Select person...</option>
              {assignableUsers.map((u) => (
                <option key={u._id} value={u._id}>
                  {u._id === user?._id ? `👤 ${u.name} (Me)` : `${u.name} · ${u.role.replace("_", " ")}${u.team ? ` · ${u.team}` : ""}`}
                </option>
              ))}
            </select>
          </Field>

          <Field label="Team" required>
            <select value={form.team} onChange={set("team")}>
              {TEAMS.map((t) => <option key={t} value={t}>{t}</option>)}
            </select>
          </Field>
        </div>

        <div className="field-row">
          <Field label="Priority">
            <select value={form.priority} onChange={set("priority")}>
              {Object.entries(PRIORITY_LABELS).map(([k, v]) => <option key={k} value={k}>{v}</option>)}
            </select>
          </Field>
          <Field label="Status">
            <select value={form.status} onChange={set("status")}>
              {Object.entries(STATUS_LABELS).map(([k, v]) => <option key={k} value={k}>{v}</option>)}
            </select>
          </Field>
        </div>

        <Field label="Due Date" required>
          <input type="date" value={form.dueDate} onChange={set("dueDate")} min={new Date().toISOString().slice(0, 10)} />
        </Field>

        {isEdit && (
          <Field label="Status Change Note">
            <input placeholder="Why is the status changing? (optional)" value={form.statusNote} onChange={set("statusNote")} />
          </Field>
        )}

        {/* Self-assign quick tip */}
        {!isEdit && (
          <div style={{ background: "#EFF6FF", borderRadius: 8, padding: "8px 12px", fontSize: 12, color: "#1D4ED8", marginBottom: 12 }}>
            💡 You can assign this task to yourself by selecting <strong>👤 (Me)</strong> in Assign To.
          </div>
        )}

        <div style={{ display: "flex", gap: 10, marginTop: 4 }}>
          <button type="button" className="btn btn-ghost" onClick={onClose} style={{ flex: 1 }}>Cancel</button>
          <button type="submit" className="btn btn-primary" disabled={loading} style={{ flex: 2 }}>
            {loading ? <span className="loader" style={{ width: 16, height: 16 }} /> : isEdit ? "Save Changes" : "Create Task"}
          </button>
        </div>
      </form>
    </Modal>
  );
}
